const body = $json.body || {};
const binary = $binary || {};
const fileKey = binary.pdf_file ? 'pdf_file' : (binary.data ? 'data' : null);

let parsedMetrics = {};
if (body.pdf_metrics_json) {
  try {
    parsedMetrics = JSON.parse(body.pdf_metrics_json);
  } catch (e) {
    parsedMetrics = {
      parse_error: String(e),
      raw_value: body.pdf_metrics_json
    };
  }
}

let parsedFinancial = {};
if (body.financial_details_json) {
  try {
    parsedFinancial = JSON.parse(body.financial_details_json);
  } catch (e) {
    parsedFinancial = {
      parse_error: String(e),
      raw_value: body.financial_details_json
    };
  }
}

const finIncome = parsedFinancial.income_statement || {};
const finBS = parsedFinancial.balance_sheet || {};
const finRatios = parsedFinancial.computed_ratios || {};
const finUnits = parsedFinancial.units || {};
const finQuality = parsedFinancial.extraction_quality || {};

function incomeCurrent(key) {
  const obj = finIncome[key] || {};
  return (obj.current ?? obj.prior ?? '');
}

function ratioValue(key) {
  const obj = finRatios[key] || {};
  return (obj.value ?? '');
}

function ratioPct(key) {
  const obj = finRatios[key] || {};
  return (obj.as_percent ?? '');
}

if (!fileKey) {
  return [{
    json: {
      ok: false,
      message: 'No PDF found. Send multipart/form-data with file field pdf_file or data.',
      receivedAt: new Date().toISOString(),
      company_name: body.company_name || '',
      quarter: body.quarter || '',
      industry: body.industry || '',
      original_field_name: '',
      file_name: '',
      mime_type: '',
      file_extension: '',
      file_size: '',
      ingest_status: 'failed_validation',
      pdf_sha256: body.pdf_sha256 || parsedMetrics.sha256 || '',
      pdf_size_bytes: body.pdf_size_bytes || parsedMetrics.file_size_bytes || '',
      pdf_page_count: body.pdf_page_count || parsedMetrics.page_count || '',
      pdf_word_count_sampled: body.pdf_word_count_sampled || ((parsedMetrics.text_stats || {}).word_count ?? ''),
      pdf_metrics_json: body.pdf_metrics_json || '',
      metrics_ingested_at: parsedMetrics.ingested_at || '',
      metrics_pdf_signature_ok: String(parsedMetrics.pdf_signature_ok ?? ''),
      metrics_chars: String(((parsedMetrics.text_stats || {}).chars ?? '')),
      metrics_nonempty_line_count: String(((parsedMetrics.text_stats || {}).nonempty_line_count ?? '')),
      metrics_number_token_count: String(((parsedMetrics.text_stats || {}).number_token_count ?? '')),
      metrics_email_count: String(((parsedMetrics.text_stats || {}).email_count ?? '')),
      metrics_url_count: String(((parsedMetrics.text_stats || {}).url_count ?? '')),
      metrics_currency_mention_count: String(((parsedMetrics.text_stats || {}).currency_mention_count ?? '')),
      metrics_image_count_in_sampled_pages: String(parsedMetrics.image_count_in_sampled_pages ?? ''),
      metrics_sampled_page_count: String(parsedMetrics.sampled_page_count ?? ''),
      metrics_preview_text: parsedMetrics.preview_text || '',
      metrics_metadata_json: JSON.stringify(parsedMetrics.metadata || {}),

      financial_details_json: body.financial_details_json || '',
      financial_currency: body.financial_currency || finUnits.currency || '',
      financial_units_label: body.financial_units_label || finUnits.units_label || '',
      financial_found_items_count: String(body.financial_found_items_count ?? finQuality.found_items_count ?? ''),
      financial_has_income_statement: String(body.financial_has_income_statement ?? finQuality.has_income_statement ?? ''),
      financial_has_balance_sheet: String(body.financial_has_balance_sheet ?? finQuality.has_balance_sheet ?? ''),

      income_total_operating_income: String(body.income_total_operating_income ?? incomeCurrent('total_operating_income') ?? ''),
      income_profit_for_period: String(body.income_profit_for_period ?? incomeCurrent('profit_for_period') ?? ''),
      bs_total_assets: String(body.bs_total_assets ?? finBS.total_assets ?? ''),

      ratio_roa: String(body.ratio_roa ?? ratioValue('roa') ?? ''),
      ratio_roa_pct: String(body.ratio_roa_pct ?? ratioPct('roa') ?? ''),
      ratio_roe: String(body.ratio_roe ?? ratioValue('roe') ?? ''),
      ratio_roe_pct: String(body.ratio_roe_pct ?? ratioPct('roe') ?? ''),
      ratio_cost_to_income: String(body.ratio_cost_to_income ?? ratioValue('cost_to_income') ?? ''),
      ratio_cost_to_income_pct: String(body.ratio_cost_to_income_pct ?? ratioPct('cost_to_income') ?? ''),
      ratio_npl_ratio: String(body.ratio_npl_ratio ?? ratioValue('npl_ratio') ?? ''),
      ratio_npl_ratio_pct: String(body.ratio_npl_ratio_pct ?? ratioPct('npl_ratio') ?? ''),
      ratio_coverage_ratio: String(body.ratio_coverage_ratio ?? ratioValue('coverage_ratio') ?? ''),
      ratio_coverage_ratio_pct: String(body.ratio_coverage_ratio_pct ?? ratioPct('coverage_ratio') ?? ''),
      ratio_loan_to_deposit: String(body.ratio_loan_to_deposit ?? ratioValue('loan_to_deposit') ?? ''),
      ratio_loan_to_deposit_pct: String(body.ratio_loan_to_deposit_pct ?? ratioPct('loan_to_deposit') ?? '')
    }
  }];
}

const file = binary[fileKey];

return [{
  json: {
    ok: true,
    message: 'PDF received successfully in n8n.',
    receivedAt: new Date().toISOString(),
    company_name: body.company_name || '',
    quarter: body.quarter || '',
    industry: body.industry || '',
    original_field_name: fileKey,
    file_name: file.fileName || '',
    mime_type: file.mimeType || '',
    file_extension: file.fileExtension || '',
    file_size: file.fileSize || '',
    ingest_status: 'received',
    pdf_sha256: body.pdf_sha256 || parsedMetrics.sha256 || '',
    pdf_size_bytes: body.pdf_size_bytes || parsedMetrics.file_size_bytes || file.fileSize || '',
    pdf_page_count: body.pdf_page_count || parsedMetrics.page_count || '',
    pdf_word_count_sampled: body.pdf_word_count_sampled || ((parsedMetrics.text_stats || {}).word_count ?? ''),
    pdf_metrics_json: body.pdf_metrics_json || '',
    metrics_ingested_at: parsedMetrics.ingested_at || '',
    metrics_pdf_signature_ok: String(parsedMetrics.pdf_signature_ok ?? ''),
    metrics_chars: String(((parsedMetrics.text_stats || {}).chars ?? '')),
    metrics_nonempty_line_count: String(((parsedMetrics.text_stats || {}).nonempty_line_count ?? '')),
    metrics_number_token_count: String(((parsedMetrics.text_stats || {}).number_token_count ?? '')),
    metrics_email_count: String(((parsedMetrics.text_stats || {}).email_count ?? '')),
    metrics_url_count: String(((parsedMetrics.text_stats || {}).url_count ?? '')),
    metrics_currency_mention_count: String(((parsedMetrics.text_stats || {}).currency_mention_count ?? '')),
    metrics_image_count_in_sampled_pages: String(parsedMetrics.image_count_in_sampled_pages ?? ''),
    metrics_sampled_page_count: String(parsedMetrics.sampled_page_count ?? ''),
    metrics_preview_text: parsedMetrics.preview_text || '',
    metrics_metadata_json: JSON.stringify(parsedMetrics.metadata || {}),

    financial_details_json: body.financial_details_json || '',
    financial_currency: body.financial_currency || finUnits.currency || '',
    financial_units_label: body.financial_units_label || finUnits.units_label || '',
    financial_found_items_count: String(body.financial_found_items_count ?? finQuality.found_items_count ?? ''),
    financial_has_income_statement: String(body.financial_has_income_statement ?? finQuality.has_income_statement ?? ''),
    financial_has_balance_sheet: String(body.financial_has_balance_sheet ?? finQuality.has_balance_sheet ?? ''),

    income_total_operating_income: String(body.income_total_operating_income ?? incomeCurrent('total_operating_income') ?? ''),
    income_profit_for_period: String(body.income_profit_for_period ?? incomeCurrent('profit_for_period') ?? ''),
    bs_total_assets: String(body.bs_total_assets ?? finBS.total_assets ?? ''),

    ratio_roa: String(body.ratio_roa ?? ratioValue('roa') ?? ''),
    ratio_roa_pct: String(body.ratio_roa_pct ?? ratioPct('roa') ?? ''),
    ratio_roe: String(body.ratio_roe ?? ratioValue('roe') ?? ''),
    ratio_roe_pct: String(body.ratio_roe_pct ?? ratioPct('roe') ?? ''),
    ratio_cost_to_income: String(body.ratio_cost_to_income ?? ratioValue('cost_to_income') ?? ''),
    ratio_cost_to_income_pct: String(body.ratio_cost_to_income_pct ?? ratioPct('cost_to_income') ?? ''),
    ratio_npl_ratio: String(body.ratio_npl_ratio ?? ratioValue('npl_ratio') ?? ''),
    ratio_npl_ratio_pct: String(body.ratio_npl_ratio_pct ?? ratioPct('npl_ratio') ?? ''),
    ratio_coverage_ratio: String(body.ratio_coverage_ratio ?? ratioValue('coverage_ratio') ?? ''),
    ratio_coverage_ratio_pct: String(body.ratio_coverage_ratio_pct ?? ratioPct('coverage_ratio') ?? ''),
    ratio_loan_to_deposit: String(body.ratio_loan_to_deposit ?? ratioValue('loan_to_deposit') ?? ''),
    ratio_loan_to_deposit_pct: String(body.ratio_loan_to_deposit_pct ?? ratioPct('loan_to_deposit') ?? '')
  },
  binary: {
    [fileKey]: file
  }
}];
